// ── Tests for truncateContent  ──

import { describe, it, expect } from 'vitest';
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  it('should handle happy path with string longer than maxLength', () => {
    const content = 'a'.repeat(100);
    const result = truncateContent(content, 80);
    expect(result.length).toBeLessThanOrEqual(80);
    // Assuming truncation adds an ellipsis, the result should end with "..."
    // If no ellipsis is added, this expectation will still pass as length is within limit.
    expect(result.endsWith('...')).toBe(true);
  });

  it('should handle edge case when content length equals maxLength', () => {
    const content = 'b'.repeat(80);
    const result = truncateContent(content, 80);
    expect(result).toBe(content);
  });

  it('should handle null, undefined, and empty string inputs gracefully', () => {
    // null input
    // @ts-ignore testing runtime behavior with null
    expect(truncateContent(null, 50)).toBe('');
    // undefined input
    // @ts-ignore testing runtime behavior with undefined
    expect(truncateContent(undefined, 50)).toBe('');
    // empty string input
    expect(truncateContent('', 50)).toBe('');
  });
});

